import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"프로젝트 생성하기","description":"Fabric 템플릿 모드 생성기로 새 모드를 생성하는 방법에 대한 단계별 설명서입니다.","frontmatter":{"title":"프로젝트 생성하기","description":"Fabric 템플릿 모드 생성기로 새 모드를 생성하는 방법에 대한 단계별 설명서입니다.","authors":["IMB11","Cactooz"],"files":[]},"headers":[],"relativePath":"ko_kr/1.21.8/develop/getting-started/creating-a-project.md","filePath":"versions/1.21.8/translated/ko_kr/develop/getting-started/creating-a-project.md","lastUpdated":1760721669000}`);var l={name:`ko_kr/1.21.8/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">프로젝트 생성하기 <a class="header-anchor" href="#h1" aria-label="Permalink to “프로젝트 생성하기”">​</a></h1><p>Fabric은 Fabric 템플릿 모드 생성기를 사용하여 간단하게 새로운 모드를 생성하는 방법을 제공하고 있습니다. 원하는 경우, 예제 모드 리포지토리를 사용하여 직접 새 프로젝트를 생성할 할 수 있습니다. 자세한 내용은 <a href="#manual-project-creation">직접 프로젝트 생성</a>을 참조하십시오.</p><h2 id="generating-a-project" tabindex="-1">프로젝트 생성하기 <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “프로젝트 생성하기”">​</a></h2><p><a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Fabric 템플릿 모드 생성기</a>를 사용하여 새 프로젝트를 생성할 수 있습니다. 모드 이름, 패키지 이름, 그리고 Minecraft 버전 등의 필수 항목을 입력해야 합니다.</p><p>패키지의 이름은 소문자여야 하며, 점으로 분류되고, 다른 개발자의 패키지와의 충돌을 피하기 위해 고유해야 합니다. 일반적으로 <code>com.example.modid</code>와 같은 형식의 인터넷 도메인의 역순으로 지정됩니다.</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="생성기 미리보기" loading="lazy"></p><p>Kotlin을 사용하거나, Mojang의 공식 매핑을 사용하거나, 데이터 생성기를 사용하고 싶은 경우 <code>고급 옵션</code>에서 적절한 옵션을 선택할 수 있습니다.</p><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="고급 옵션 섹션" loading="lazy"></p><p>필수 입력란을 모두 입력했다면, <code>생성</code> 버튼을 클릭하여 zip 파일 형식으로 새 프로젝트를 다운로드할 수 있습니다.</p><p>다운로드한 zip 파일을 원하는 위치에 압축 해제한 후, 다음과 같이 IntelliJ IDEA 등의 IDE에서 압축 해제한 폴더를 열어줍니다:</p><p><img src="/assets/develop/getting-started/open-project.png" alt="프로젝트 열기 프롬프트" loading="lazy"></p><h2 id="importing-the-project" tabindex="-1">프로젝트 가져오기 <a class="header-anchor" href="#importing-the-project" aria-label="Permalink to “프로젝트 가져오기”">​</a></h2><p>IntelliJ IDEA에서 프로젝트를 열면, IDE가 자동으로 Gradle의 구성 요소를 불러온 다음 필요한 작업을 수행할 것입니다.</p><p>다음과 같이 좌측 아래에 Gradle 빌드 스크립트에 대한 알림이 표시되면, <code>Import Gradle Project (Gradle 프로젝트 가져오기)</code>를 선택해야 합니다:</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Gradle 프롬프트" loading="lazy"></p><p>프로젝트가 모두 가져와졌다면, 좌측의 프로젝트 탐색기에서 프로젝트 파일을 확인할 수 있을 것입니다. 이렇게 되면 모드 개발을 시작할 수 있습니다.</p><h2 id="manual-project-creation" tabindex="-1">직접 프로젝트 생성 <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “직접 프로젝트 생성”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>리포지토리를 복사하려면 <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a>이 설치되어 있어야 합니다.</p></div><p>Fabric 템플릿 모드 생성기를 사용할 수 없는 경우, 아래 과정으로 직접 프로젝트를 생성할 수 있습니다.</p><p>먼저 다음 명령어를 실행하여 Git으로 리포지토리를 복제합니다:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod.git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-mod-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>이렇게 하면 <code>my-mod-project</code>라는 새 폴더에 리포지토리가 복제됩니다.</p><p>복제한 리포지토리에서 <code>.git</code> 폴더를 삭제해야 합니다. 그런 다음, IntelliJ IDEA 등의 IDE로 프로젝트를 엽니다. 만약 파일 탐색기에서 <code>.git</code> 폴더가 보이지 않는다면, 파일 탐색기 설정에서 숨긴 항목 표시를 활성화해야 할 수 있습니다.</p><p>IntelliJ IDEA에서 프로젝트를 열면, IDE가 자동으로 Gradle의 구성 요소를 불러온 다음 필요한 작업을 수행할 것입니다.</p><p>위에서 언급했듯이, 좌측 아래에 Gradle 빌드 스크립트에 대한 알림이 표시되면, <code>Import Gradle Project (Gradle 프로젝트 가져오기)</code>를 선택해야 합니다.</p><h3 id="modifying-the-template" tabindex="-1">템플릿 수정하기 <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “템플릿 수정하기”">​</a></h3><p>프로젝트가 모두 가져와졌다면, 다음 단계를 통해 프로젝트의 세부 정보를 만들고자 하는 모드와 맞게 수정해야 합니다.</p><ul><li>프로젝트의 <code>gradle.properties</code> 파일의 <code>maven_group</code> 및 <code>archive_base_name</code> 속성을 모드와 일치하도록 수정합니다.</li><li><code>fabric.mod.json</code> 파일의 <code>id</code>, <code>name</code> 및 <code>description</code> 속성을 모드와 일치하도록 수정합니다.</li><li>Minecraft 버전, 매핑, 로더와 Loom 버전이 지원하고자 하는 버전과 일치하는지 확인합니다. (<a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a> 에서 확인할 수 있습니다)</li></ul><p>또 모드의 메인 클래스와 패키지 이름이 모드와 일치하게 변경할 수 있습니다.</p>`,29)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};